from django.contrib.auth import authenticate, login
from django.utils.timezone import now
from saml2 import BINDING_HTTP_POST
from saml2.client import Saml2Client
from saml2.response import StatusResponse

class SAMLServiceProvider:
    def __init__(self):
        self.saml_client = Saml2Client(config={
            "service": {
                "sp": {
                    "endpoints": {
                        "assertion_consumer_service": [
                            ("", BINDING_HTTP_POST)
                        ],
                        "single_logout_service": [
                            ("", BINDING_HTTP_POST)
                        ]
                    },
                    "authn_requests": {
                        "comparison": "minimum"
                    }
                }
            }
        })

    def handle_saml_post(self, request):
        response = self.saml_client.parse_authn_request_response(
            request.POST["SAMLResponse"],
            entity="https://example.com/sp",
            destination="https://example.com/idp"
        )

        if not response:
            return None

        status = StatusResponse.from_string(response)
        if status.status_code != "urn:oasis:names:tc:SAML:2.0:status:Success":
            return None

        assertion = status.assertion
        user_info = {}

        for attribute in assertion.attribute_statement.attributes:
            name = attribute.name
            values = [value.text for value in attribute.attribute_values]
            if len(values) > 0:
                user_info[name] = values[0]

        user = authenticate(request, **user_info)
        login(request, user)

        return user